import { useState, useEffect } from "react";
import { ethers, BigNumber } from "ethers";

const CONTRACT_ADDRESS = "0x0c298cD0838BF8e151CDA0Ae19C3B698b453632F";

const ABI = [
  // ... paste your full ABI here ...
];

export const useToken = (signer: ethers.Signer | null) => {
  const [contract, setContract] = useState<ethers.Contract | null>(null);

  useEffect(() => {
    if (!signer) return;
    const token = new ethers.Contract(CONTRACT_ADDRESS, ABI, signer);
    setContract(token);
  }, [signer]);

  // ------------------------
  // Read functions
  // ------------------------
  const balanceOf = async (address: string): Promise<BigNumber> => {
    if (!contract) return BigNumber.from(0);
    return await contract.balanceOf(address);
  };

  const totalSupply = async (): Promise<BigNumber> => {
    if (!contract) return BigNumber.from(0);
    return await contract.totalSupply();
  };

  const name = async (): Promise<string> => {
    if (!contract) return "";
    return await contract.name();
  };

  const symbol = async (): Promise<string> => {
    if (!contract) return "";
    return await contract.symbol();
  };

  const decimals = async (): Promise<number> => {
    if (!contract) return 18;
    return await contract.decimals();
  };

  const maxSupply = async (): Promise<BigNumber> => {
    if (!contract) return BigNumber.from(0);
    return await contract.MAX_SUPPLY();
  };

  const faucetCooldown = async (): Promise<number> => {
    if (!contract) return 0;
    const cooldown: BigNumber = await contract.FAUCET_COOLDOWN();
    return cooldown.toNumber();
  };

  const lastRequestTime = async (user: string): Promise<number> => {
    if (!contract) return 0;
    const time: BigNumber = await contract.lastRequestTime(user);
    return time.toNumber();
  };

  const getRemainingCooldown = async (user: string): Promise<number> => {
    if (!contract) return 0;
    const time: BigNumber = await contract.getRemainingCooldown(user);
    return time.toNumber();
  };

  // ------------------------
  // Write functions
  // ------------------------
  const requestTokens = async (): Promise<void> => {
    if (!contract) return;
    const tx = await contract.requestTokens();
    await tx.wait();
  };

  const mint = async (to: string, amount: string | BigNumber): Promise<void> => {
    if (!contract) return;

    // convert string amounts to BigNumber if needed
    const amt: BigNumber = typeof amount === "string" ? ethers.utils.parseUnits(amount, 18) : amount;
    const tx = await contract.mint(to, amt);
    await tx.wait();
  };

  const transfer = async (to: string, amount: string | BigNumber): Promise<void> => {
    if (!contract) return;

    const amt: BigNumber = typeof amount === "string" ? ethers.utils.parseUnits(amount, 18) : amount;
    const tx = await contract.transfer(to, amt);
    await tx.wait();
  };

  return {
    contract,
    balanceOf,
    totalSupply,
    name,
    symbol,
    decimals,
    maxSupply,
    faucetCooldown,
    lastRequestTime,
    getRemainingCooldown,
    requestTokens,
    mint,
    transfer,
  };
};
